export const MessageAvatarDemo = (): Html =>
  stack(
    [
      Message<never>({
        children: [
          MessageAvatar<never>({ children: [avatar(rabbitProfile)] }),
          MessageContent<never>({
            children: [
              bubble(
                ['The build failed during dependency installation.'],
                true,
              ),
            ],
          }),
        ],
      }),
      Message<never>({
        align: 'end',
        role: 'user',
        children: [
          MessageAvatar<never>({ children: [avatar(rabbitProfile)] }),
          MessageContent<never>({
            children: [bubble(['Can you share the exact error?'])],
          }),
